@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">
                    &larr; Move Left
                </button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@isSaving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        isSaving = true;
        await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        isSaving = false;
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column: header with count, task cards, and add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="HandleMoveLeft"
                          OnMoveRight="HandleMoveRight" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleTaskSave" OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showAddForm;

    private async Task HandleMoveLeft(int taskId)
    {
        await OnMoveTask.InvokeAsync((taskId, "left"));
    }

    private async Task HandleMoveRight(int taskId)
    {
        await OnMoveTask.InvokeAsync((taskId, "right"));
    }

    private async Task HandleTaskSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnTaskCreated.InvokeAsync(formData);
        showAddForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     TodoCount="TodoTasks.Count"
                     InProgressCount="InProgressTasks.Count"
                     DoneCount="DoneTasks.Count"
                     OverdueCount="OverdueTasks.Count" />

    <TaskSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="args => HandleCreateTask(args, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="args => HandleCreateTask(args, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="args => HandleCreateTask(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    // Unfiltered lists by status (used for summary counts)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueTasks => allTasks.Count(t => t.DueDate < DateTime.Today);

    // Filtered lists (search applied)
    private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm)) return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task HandleMoveTask((int TaskId, string Direction) args)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleCreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) formData,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

